import pytest

from your_module import truncate  # replace "your_module" with the actual module name


@pytest.mark.parametrize(
    "s,max_len,expected",
    [
        ("hello", 10, "hello"),
        ("hello", 5, "hello"),
        ("", 5, ""),
        ("", 0, ""),
    ],
)
def test_truncate_returns_original_when_length_is_within_limit(s, max_len, expected):
    assert truncate(s, max_len) == expected


@pytest.mark.parametrize(
    "s,max_len,expected",
    [
        ("hello world", 8, "hello..."),
        ("abcdef", 4, "a..."),
        ("abcdef", 3, "..."),
    ],
)
def test_truncate_with_default_suffix(s, max_len, expected):
    assert truncate(s, max_len) == expected


@pytest.mark.parametrize(
    "s,max_len,suffix,expected",
    [
        ("hello world", 8, "…", "hello w…"),
        ("abcdef", 4, "~", "abc~"),
        ("abcdef", 5, "--", "abc--"),
        ("abcdef", 3, "", "abc"),
    ],
)
def test_truncate_with_custom_suffix(s, max_len, suffix, expected):
    assert truncate(s, max_len, suffix) == expected


def test_truncate_handles_unicode_characters():
    assert truncate("😀😃😄😁", 3, "…") == "😀😃…"


def test_truncate_when_max_len_is_less_than_suffix_length_documents_current_behavior():
    # Current implementation uses negative slicing:
    # "abcdef"[:2 - 3] + "..." == "abcde..."
    assert truncate("abcdef", 2) == "abcde..."


@pytest.mark.parametrize(
    "max_len,expected",
    [
        (0, "abc..."),
        (-1, "ab..."),
        (-10, "..."),
    ],
)
def test_truncate_with_zero_or_negative_max_len_documents_current_behavior(max_len, expected):
    assert truncate("abcdef", max_len) == expected


def test_suffix_is_not_used_when_string_does_not_need_truncation():
    assert truncate("abc", 3, suffix=None) == "abc"


@pytest.mark.parametrize(
    "s,max_len,suffix",
    [
        (None, 3, "..."),
        ("abcdef", "3", "..."),
        ("abcdef", 3, None),
        ("abcdef", 3, ["..."]),
    ],
)
def test_truncate_raises_type_error_for_invalid_argument_types(s, max_len, suffix):
    with pytest.raises(TypeError):
        truncate(s, max_len, suffix)
